import React, { useState, useEffect } from 'react';
import { MapPin, Search, Globe, ShoppingBag } from 'lucide-react';
import { dbSimulador } from '../services/dbSimulador';

const PanelCliente = () => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [ofertasFiltradas, setOfertasFiltradas] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  
  const [provinciaSel, setProvinciaSel] = useState('Tucumán');
  const [ciudadSel, setCiudadSel] = useState('Todas');
  const [zonaSel, setZonaSel] = useState('Todas las zonas');

  useEffect(() => {
    setTodasLasOfertas(dbSimulador.getOfertasGlobales());
  }, []);

  useEffect(() => {
    const filtrado = todasLasOfertas.filter(o => {
      const matchBusqueda = o.producto.toLowerCase().includes(busqueda.toLowerCase());
      const matchProv = o.provincia === provinciaSel;
      const matchCiudad = ciudadSel === 'Todas' || o.ciudad === ciudadSel;
      const matchZona = zonaSel === 'Todas las zonas' || o.zona === zonaSel;
      return matchBusqueda && matchProv && matchCiudad && matchZona;
    });
    setOfertasFiltradas(filtrado);
  }, [busqueda, provinciaSel, ciudadSel, zonaSel, todasLasOfertas]);

  const ciudadesDisponibles = [...new Set(todasLasOfertas.filter(o => o.provincia === provinciaSel).map(o => o.ciudad))];
  const zonasDisponibles = ['Todas las zonas', ...new Set(todasLasOfertas.filter(o => o.ciudad === ciudadSel || ciudadSel === 'Todas').map(o => o.zona))];

  return (
    <div style={{ background: '#f8fafc', minHeight: '100vh', paddingBottom: '50px' }}>
      <div style={navStyle}>
        <div style={selectorContainer}>
          <div style={group}>
            <Globe size={18} color="#f97316" />
            <select value={provinciaSel} onChange={(e) => {setProvinciaSel(e.target.value); setCiudadSel('Todas');}} style={selectStyle}>
              <option value="Tucumán">Tucumán</option>
              <option value="Salta">Salta</option>
              <option value="Buenos Aires">Buenos Aires</option>
            </select>
          </div>
          <div style={divider} />
          <div style={group}>
            <MapPin size={18} color="#f97316" />
            <select value={ciudadSel} onChange={(e) => {setCiudadSel(e.target.value); setZonaSel('Todas las zonas');}} style={selectStyle}>
              <option value="Todas">Todas las ciudades</option>
              {ciudadesDisponibles.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
        </div>
        
        <div style={tabContainer}>
          {zonasDisponibles.map(z => (
            <button key={z} onClick={() => setZonaSel(z)} style={zonaSel === z ? tabActive : tabStyle}>{z}</button>
          ))}
        </div>
      </div>

      <div style={{ padding: '20px 5%' }}>
        <div style={searchBar}>
          <Search size={22} color="#94a3b8" />
          <input 
            placeholder={`Buscar en ${ciudadSel === 'Todas' ? provinciaSel : ciudadSel}...`} 
            style={inputStyle}
            onChange={(e) => setBusqueda(e.target.value)}
          />
        </div>

        <div style={grid}>
          {ofertasFiltradas.length > 0 ? ofertasFiltradas.map(o => (
            <div key={o.id} style={card}>
              <div style={badge}>-{Math.round(((o.precioViejo - o.precioNuevo)/o.precioViejo)*100)}%</div>
              <div style={{ padding: '20px' }}>
                <span style={localLabel}>{o.nombreLocal}</span>
                <h3 style={title}>{o.producto}</h3>
                <p style={address}><MapPin size={14} /> {o.direccionLocal}, {o.zona}</p>
                <div style={priceRow}>
                  <span style={price}>${o.precioNuevo}</span>
                  <span style={oldPrice}>${o.precioViejo}</span>
                </div>
                <button style={btnAction}><ShoppingBag size={18} /> Reservar Oferta</button>
              </div>
            </div>
          )) : (
            <div style={{ gridColumn: '1/-1', textAlign: 'center', padding: '50px', color: '#94a3b8' }}>
              <h3>No hay ofertas registradas en esta zona.</h3>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

// --- ESTILOS ---
const navStyle = { background: 'white', padding: '15px 5%', borderBottom: '1px solid #e2e8f0', position: 'sticky', top: 0, zIndex: 100 };
const selectorContainer = { display: 'flex', gap: '20px', background: '#f1f5f9', padding: '10px 20px', borderRadius: '30px' };
const group = { display: 'flex', alignItems: 'center', gap: '8px' };
const divider = { width: '1px', background: '#cbd5e1', height: '20px' };
const selectStyle = { border: 'none', background: 'transparent', fontWeight: '700', outline: 'none', cursor: 'pointer', fontSize: '0.9rem' };
const tabContainer = { display: 'flex', gap: '10px', marginTop: '15px', overflowX: 'auto', paddingBottom: '5px' };
const tabStyle = { padding: '8px 18px', borderRadius: '20px', border: '1px solid #e2e8f0', background: 'white', whiteSpace: 'nowrap', cursor: 'pointer', fontSize: '0.85rem', fontWeight: '600', color: '#64748b' };
const tabActive = { ...tabStyle, background: '#1e293b', color: 'white', borderColor: '#1e293b' };
const searchBar = { display: 'flex', background: 'white', padding: '15px 25px', borderRadius: '15px', border: '1px solid #e2e8f0', marginBottom: '30px', alignItems: 'center' };
const inputStyle = { border: 'none', outline: 'none', flex: 1, marginLeft: '12px', fontSize: '1rem' };
const grid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '25px' };
const card = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', position: 'relative', transition: '0.2s' };
const badge = { position: 'absolute', top: '15px', right: '15px', background: '#ef4444', color: 'white', padding: '5px 10px', borderRadius: '8px', fontWeight: '900', fontSize: '0.8rem' };
const localLabel = { fontSize: '0.75rem', color: '#f97316', fontWeight: '800', textTransform: 'uppercase', letterSpacing: '0.5px' };
const title = { margin: '8px 0', fontSize: '1.25rem', fontWeight: '700', color: '#1e293b' };
const address = { fontSize: '0.8rem', color: '#64748b', display: 'flex', alignItems: 'center', gap: '5px' };
const priceRow = { display: 'flex', alignItems: 'baseline', gap: '10px', marginTop: '15px' };
const price = { fontSize: '1.8rem', fontWeight: '900', color: '#1e293b' };
const oldPrice = { textDecoration: 'line-through', color: '#94a3b8', fontSize: '1rem' };
const btnAction = { width: '100%', marginTop: '20px', padding: '14px', borderRadius: '12px', border: 'none', background: '#1e293b', color: 'white', fontWeight: 'bold', cursor: 'pointer', display: 'flex', justifyContent: 'center', gap: '10px', fontSize: '1rem' };

export default PanelCliente;
